INSERT INTO `martyrs` (`name`,`bio`,`tracks`,`family_status`,`lat`,`lng`,`route`,`route_labels`,`timeline`) VALUES
('赵一曼','赵一曼（1905-1936），原名李坤泰，四川宜宾人，抗日民族英雄。1926年加入中国共产党，先后在莫斯科中山大学和黄埔军校学习。1932年前往东北参加抗日斗争，任东北抗联第三军第二团政委，率领战士多次与日军展开激战。1935年战斗中负伤被俘，遭受日军残酷酷刑始终坚贞不屈。1936年8月英勇就义于珠河县，年仅31岁。','四川宜宾 → 上海 → 武汉 → 哈尔滨','临刑前给年幼的儿子宁儿写下感人遗书，嘱咐"不要忘记你的母亲是为国而牺牲的"。丈夫陈达邦同为革命者，儿子陈掖贤在新中国成立后被找到并妥善安置。',45.750000,126.650000,
INSERT INTO `letters` (`martyr_id`,`content`,`photos`,`ai_explanation`) VALUES
(1,'宁儿：\n\n母亲对于你没有能尽到教育的责任，实在是遗憾的事情。母亲因为坚决地做了反满抗日的斗争，今天已经到了牺牲的前夕了。\n\n母亲和你在生前是永久没有再见的机会了。希望你，宁儿啊！赶快成人，来安慰你地下的母亲！\n\n我最亲爱的孩子啊！母亲不用千言万语来教育你，就用实行来教育你。在你长大成人之后，希望不要忘记你的母亲是为国而牺牲的！\n\n你的母亲 赵一曼\n一九三六年八月二日','[{"url":"/photos/zhaoyiman/zhaoyiman1.jpg","desc":"赵一曼历史照片 (1)"},{"url":"/photos/zhaoyiman/zhaoyiman2.jpg","desc":"赵一曼历史照片 (2)"},{"url":"/photos/zhaoyiman/zhaoyiman3.jpg","desc":"赵一曼历史照片 (3)"},{"url":"/photos/zhaoyiman/zhaoyiman4.jpg","desc":"赵一曼历史照片 (4)"},{"url":"/photos/zhaoyiman/zhaoyiman5.jpg","desc":"赵一曼历史照片 (5)"},{"url":"/photos/zhaoyiman/zhaoyiman6.jpg","desc":"赵一曼历史照片 (6)"}]','这封信是赵一曼烈士在就义前写给儿子宁儿的遗书。信中充满母爱与不舍，也体现了为国牺牲的坚定信念。"母亲是为国而牺牲的"展现了革命先烈将个人命运与国家民族命运紧密相连的崇高精神。'),
INSERT INTO `replies` (`letter_id`,`user_id`,`content`,`created_at`) VALUES
(1, 2, '读完赵一曼烈士写给宁儿的遗书，眼眶湿润了。一位母亲在生命最后时刻对孩子的牵挂，让我深刻体会到革命先辈的伟大。', '2025-01-16 10:30:00'),
(1, 5, '作为一名大学生志愿者，看到"母亲不用千言万语来教育你"这句话，我想起了自己的妈妈。先烈们舍小家为大家的精神永远值得铭记。', '2025-01-20 14:22:00'),
(1, 8, '宁儿长大后一定会为有这样的母亲而骄傲。赵一曼烈士，您的精神激励着我们每一代青年人！', '2025-02-03 09:15:00'),
(1, 12, '今天的幸福来之不易，是无数像赵一曼烈士这样的英雄用鲜血换来的。我们当代青年一定要珍惜。', '2025-03-10 16:40:00'),
(1, 18, '在课堂上学到过赵一曼的故事，但读到她亲笔写给儿子的信，那种震撼完全不同。致敬！', '2025-04-22 11:05:00'),
(1, 25, '每次读这封信都会落泪。母爱是伟大的，为国牺牲的母爱更是崇高的。赵一曼烈士永垂不朽。', '2025-06-15 20:30:00'),
(1, 35, '我是学前教育专业的学生，将来一定要把赵一曼的故事讲给孩子们听，让红色基因代代相传。', '2025-09-01 08:50:00'),
(1, 42, '参加完这次志愿活动，我才真正理解了什么叫"信仰的力量"。赵一曼烈士，我们不会忘记您。', '2026-01-10 15:20:00'),
(2, 3, '杨靖宇将军在冰天雪地中坚持战斗到最后一刻，读完家书我热泪盈眶。这就是中华民族的脊梁！', '2025-01-25 13:10:00'),
(2, 7, '想到杨靖宇将军牺牲时胃里只有草根和棉絮，我的心被深深刺痛了。今天吃饱穿暖的我们有什么理由不努力？', '2025-02-14 17:30:00'),
(2, 15, '我是东北人，从小听着杨靖宇将军的故事长大。这封家书让我更加了解他作为父亲和丈夫的柔情一面。', '2025-04-05 09:45:00'),
(2, 22, '将军百战身名裂，向河梁、回头万里。杨靖宇将军的英勇事迹永远是我们前行的灯塔。', '2025-07-20 14:55:00'),
(2, 30, '作为历史学专业的学生，整理杨靖宇将军的资料时数次被感动。这封家书是最珍贵的历史见证。', '2025-10-18 11:25:00'),
(2, 45, '白山黑水间的英魂，永远守护着这片土地。致敬杨靖宇将军！', '2026-02-05 16:00:00'),
(3, 4, '刘胡兰15岁就英勇就义，和我们差不多大的年纪。她的勇气让我深感惭愧，也激励我要更加坚强。', '2025-02-08 10:00:00'),
(3, 10, '"生的伟大，死的光荣"，毛主席的题词完美诠释了刘胡兰的一生。我们要继承她的精神。', '2025-03-28 15:30:00'),
(3, 20, '作为同龄女生，我无法想象刘胡兰面对铡刀时的勇气。她是我心中最伟大的女英雄。', '2025-06-12 09:20:00'),
(3, 38, '读完家书我在想，是什么样的信仰能让一个少女如此从容面对死亡？这就是共产主义信仰的力量。', '2025-11-05 14:10:00'),
(4, 6, '黄继光用胸膛堵住枪眼的英勇壮举震撼了我。读完家书更了解到他对母亲的深情和报国的决心。', '2025-01-30 11:45:00'),
(4, 14, '我爷爷也是志愿军老兵，他说当年战场上像黄继光这样的英雄太多了。向所有志愿军烈士致敬！', '2025-04-15 16:20:00'),
(4, 28, '家书中那句对母亲的承诺令人动容。黄继光烈士，您兑现了对祖国的承诺，我们会铭记永远。', '2025-08-08 10:35:00'),
(5, 9, '邱少云在烈火中一动不动的故事，小学课本就学过。如今读到家书，才真正感受到他内心的坚定。', '2025-02-20 13:50:00'),
(5, 16, '纪律是胜利的保证，邱少云烈士用生命诠释了什么是铁的纪律。作为学生党员，我深受教育。', '2025-05-10 08:40:00'),
(5, 33, '每次想到邱少云忍受烈火焚烧却纹丝不动，我就觉得自己遇到的困难根本不算什么。', '2025-09-25 17:15:00'),
(6, 11, '董存瑞托举炸药包的画面永远定格在历史中。读了家书才知道他牺牲时年仅19岁，太年轻了。', '2025-03-05 14:30:00'),
(6, 19, '"为了新中国，前进！"这句话振聋发聩。董存瑞烈士的牺牲精神永远激励我们奋勇向前。', '2025-06-28 10:10:00'),
(6, 40, '作为建筑工程专业的学生，看到董存瑞炸碉堡的故事特别有感触。我们建设的每一栋楼都是烈士用生命换来的和平成果。', '2025-12-15 09:00:00'),
(7, 2, '左权将军写给妻子的家书充满柔情，一位铁骨铮铮的将军也有如此细腻的感情。读完深受感动。', '2025-01-18 15:20:00'),
(7, 13, '太行山上的英灵！左权将军是抗日战争中牺牲的最高级别将领，他的家书是最珍贵的革命文物。', '2025-03-22 11:00:00'),
(7, 21, '作为文物保护志愿者，能参与修复左权将军家书照片是我最大的荣幸。每一个字都承载着历史的重量。', '2025-05-30 16:45:00'),
(7, 29, '"志兰，亲爱的"——将军笔下的温柔让人泪目。战火中的爱情更加动人。', '2025-08-12 13:25:00'),
(7, 36, '我们学校组织去左权县参观纪念馆，站在将军雕像前我默默读完了这封家书。', '2025-10-28 10:55:00'),
(7, 48, '左权将军和妻子的通信中处处体现着对革命胜利的信心和对家人的深爱，令人敬仰。', '2026-02-20 14:35:00'),
(8, 4, '江姐的故事通过《红岩》影响了几代人。读到她写给儿子的信，感受到一位革命母亲的坚强与柔情。', '2025-02-10 10:20:00'),
(8, 17, '竹签子钉入十指的酷刑都没能让江姐屈服，这种意志力让我深深折服。致敬江姐！', '2025-04-25 15:45:00'),
(8, 23, '渣滓洞的阴暗牢房里，江姐依然保持着革命乐观主义精神。她是真正的巾帼英雄。', '2025-07-08 09:30:00'),
(8, 31, '我是重庆本地学生，从小就去渣滓洞白公馆参观。江姐的家书每次读都有新的感悟。', '2025-09-15 14:00:00'),
(8, 44, '作为思政课的实践活动来读这封家书，比任何课本上的文字都更有说服力。', '2026-01-20 11:30:00'),
(9, 6, '张自忠将军战死沙场，以身殉国。他的家书体现了一位军人对国家的忠诚和对家人的眷恋。', '2025-02-28 16:10:00'),
(9, 26, '抗日战争中牺牲的最高将领之一，张自忠将军的家国情怀令人肃然起敬。', '2025-07-15 10:20:00'),
(9, 47, '将军的遗书中没有一丝畏惧，只有对民族复兴的期盼。这种精神值得我们永远学习。', '2026-03-01 09:45:00'),
(10, 8, '"为人进出的门紧锁着，为狗爬出的洞敞开着"——叶挺将军的《囚歌》和家书一样振奋人心。', '2025-03-15 13:40:00'),
(10, 24, '新四军军长的铮铮铁骨在家书中展现得淋漓尽致。他选择了自由，也选择了牺牲。', '2025-07-28 15:55:00'),
(10, 39, '叶挺将军的家书让我思考自由的意义：真正的自由是为信仰而战。', '2025-11-20 10:15:00'),
(11, 10, '向警予是中国共产党第一位女中央委员，她的家书展现了早期女性革命者的坚定信念。', '2025-03-08 11:30:00'),
(11, 32, '三八妇女节读到向警予的家书特别有感触，她为妇女解放事业奋斗了一生。', '2025-08-20 16:00:00'),
(12, 7, '四行仓库保卫战的壮举让全世界看到了中国军人的勇气。谢晋元将军的家书饱含对家人的思念。', '2025-03-20 14:25:00'),
(12, 27, '八百壮士的故事看过电影，但读到谢晋元的家书才感受到真实的历史温度。', '2025-08-05 10:50:00'),
(12, 43, '上海四行仓库纪念馆我去参观过，现在读到家书原文更加感动。', '2026-01-05 15:30:00'),
(13, 3, '"砍头不要紧，只要主义真"——夏明翰的就义诗家喻户晓。读完家书更感受到他的革命豪情。', '2025-02-15 09:10:00'),
(13, 34, '夏明翰牺牲时年仅28岁，但他的精神跨越了百年。作为同龄人，我被深深震撼。', '2025-10-01 14:40:00'),
(14, 15, '关向应将军是贺龙元帅的老搭档，他的家书体现了革命战友间的深厚情谊。', '2025-04-10 11:20:00'),
(14, 41, '读到关向应病逝前的嘱托，我理解了什么叫"鞠躬尽瘁，死而后已"。', '2025-12-22 16:15:00'),
(15, 9, '寻淮洲牺牲时年仅22岁就已经是军团长了，读完家书感叹革命年代英雄出少年。', '2025-03-25 10:35:00'),
(15, 37, '这么年轻就能担此重任，寻淮洲烈士的能力和勇气都令人钦佩。', '2025-11-08 13:20:00'),
(16, 11, '陈延年和陈乔年兄弟俩都为革命献身，他们的父亲是陈独秀。一门忠烈，令人敬仰。', '2025-04-18 15:50:00'),
(16, 46, '看过《觉醒年代》后来读陈延年的家书，更加理解了那一代青年的理想和担当。', '2026-02-15 09:30:00'),
(17, 14, '陈乔年临刑前说"让子孙后代享受前人披荆斩棘的幸福吧"，这句话让我泪流满面。', '2025-04-20 14:05:00'),
(17, 49, '兄弟二人先后牺牲，他们的家书是最好的家风教育教材。', '2026-03-05 11:00:00'),
(18, 16, '瞿秋白从容就义前写的家书充满文人的浪漫和革命者的坚定，两种气质完美融合。', '2025-05-15 10:40:00'),
(18, 50, '一介书生，满腔热血。瞿秋白先生用笔和生命践行了自己的信仰。', '2026-03-08 16:20:00'),
(19, 20, '赵世炎26岁就英勇就义，他的家书展现了早期共产党人对革命事业的赤诚之心。', '2025-06-10 11:15:00'),
(19, 36, '在法国留学时就投身革命，赵世炎的选择让我思考当代青年的使命。', '2025-10-30 14:50:00'),
(20, 19, '戴安兰将军远征缅甸为国捐躯，他写给妻子的家书中对家乡和亲人的思念令人动容。', '2025-06-20 15:30:00'),
(20, 33, '中国远征军的故事太感人了。戴安兰将军的家书让我们看到了那段被遗忘的历史。', '2025-09-28 10:45:00'),
(21, 3, '赵尚志将军是东北抗联的灵魂人物，他的家书充满了对日寇的愤怒和对胜利的信念。', '2025-02-25 13:00:00'),
(21, 13, '黑土地上的英雄！赵尚志将军和杨靖宇将军并肩作战的故事永远激励着东北儿女。', '2025-05-05 09:20:00'),
(21, 28, '我奶奶老家在哈尔滨，小时候听她讲过赵尚志的传奇故事。今天读到家书感觉格外亲切。', '2025-08-15 15:10:00'),
(21, 40, '冰天雪地里的游击战争，是怎样的意志才能坚持下来？赵尚志将军是真正的硬汉。', '2025-12-10 11:40:00'),
(21, 51, '寒假回东北参观了赵尚志纪念馆，结合这封家书更加深了我对抗联精神的理解。', '2026-03-10 10:00:00'),
(22, 5, '刘志丹是陕北红军的创建者，他的家书朴实真挚，体现了一个共产党人的初心。', '2025-03-12 14:30:00'),
(22, 17, '毛主席说刘志丹"群众领袖，民族英雄"，读完家书我对这八个字有了更深的理解。', '2025-05-25 10:00:00'),
(22, 29, '刘志丹将军创建的陕甘革命根据地为红军长征提供了落脚点，功不可没。', '2025-08-22 16:35:00'),
(22, 44, '志丹县就是以他的名字命名的。一个人的名字成为一个县的名字，这是何等的荣耀。', '2026-01-15 13:25:00'),
(23, 6, '恽代英是五四运动的先驱，他的家书中的革命理想至今仍然闪耀着光芒。', '2025-04-04 11:55:00'),
(23, 38, '恽代英说"我身上没有一件值钱的东西，只有一副近视眼镜"。清廉的品格令人敬仰。', '2025-11-12 09:30:00'),
(24, 10, '"清贫，洁白朴素的生活，正是我们革命者能够战胜许多困难的地方！"方志敏的清贫精神永不过时。', '2025-03-30 15:15:00'),
(24, 21, '方志敏在狱中写下《可爱的中国》和这封家书，用文字描绘了他心中美好中国的蓝图。', '2025-06-18 10:25:00'),
(24, 46, '今天的中国已经如方志敏所愿，成为了那个"可爱的中国"。告慰先烈，吾辈自强！', '2026-02-10 14:45:00'),
(25, 4, '李大钊先生是中国共产主义运动的先驱，他的家书中对后辈的殷切期望让人感动。', '2025-02-12 10:50:00'),
(25, 23, '北大红楼前驻足良久，想到李大钊先生当年在这里传播马克思主义。读完家书更加崇敬。', '2025-07-04 13:15:00'),
(25, 47, '先生说的"铁肩担道义"至今回响。作为新时代的青年，我们也要扛起自己的担当。', '2026-02-28 09:10:00'),
(26, 12, '蔡和森和向警予的革命爱情故事是那个时代的佳话。他的家书充满了对理想的执着。', '2025-04-08 14:35:00'),
(26, 34, '蔡和森最早提出建立共产党的主张，他的远见卓识在家书中可见一斑。', '2025-10-05 11:05:00'),
(29, 7, '彭湃烧了自己的地契把土地分给农民，这种大无畏的革命精神在家书中体现得淋漓尽致。', '2025-03-18 16:00:00'),
(29, 42, '农民运动大王的家书如此朴实，没有华丽辞藻，却句句发自肺腑。', '2026-01-08 10:40:00'),
(30, 18, '作为壮族儿女的杰出代表，韦拔群的家书让我为自己的民族骄傲。', '2025-05-20 15:25:00'),
(30, 37, '百色起义的英雄，韦拔群为广西各族人民的解放事业献出了生命。', '2025-11-15 10:10:00'),
(31, 22, '陈康容从海外归来参加革命的选择令人敬佩。她的家书展现了华侨青年的爱国赤心。', '2025-07-10 13:50:00'),
(31, 43, '作为华侨子弟，读到陈康容的家书特别有共鸣。祖国永远是海外游子的根。', '2026-01-12 14:20:00'),
(32, 25, '红二十五军在吴焕先的带领下完成了长征中最先到达陕北的壮举。他的家书充满了必胜的信念。', '2025-07-25 11:30:00'),
(33, 30, '罗炳辉将军从普通士兵成长为高级将领，他的家书中那种保护百姓的朴素情感令人动容。', '2025-09-08 16:05:00'),
(34, 26, '张太雷在广州起义中英勇牺牲，他写给家人的最后一封信充满了对革命胜利的憧憬。', '2025-08-02 10:15:00'),
(34, 41, '广州起义虽然失败了，但张太雷等烈士的牺牲为革命积累了宝贵的经验。', '2025-12-20 14:55:00'),
(35, 31, '黄公略与毛主席、朱德、彭德怀并列为井冈山时期的著名将领。他的家书透露出对根据地建设的坚定信心。', '2025-09-20 13:40:00'),
(35, 48, '井冈山精神在黄公略的家书中得到了最好的诠释。星星之火，可以燎原！', '2026-02-25 11:10:00');
INSERT INTO `projects` (`title`,`description`,`category`) VALUES
('修复抗战老兵王老先生家庭照片','王老先生是一位95岁的抗战老兵，家中珍藏着几张珍贵的家庭合影，年代久远已严重褪色破损。','照片修复'),
('采访抗美援朝老兵张爷爷','张爷爷今年92岁，曾参加上甘岭战役。需要志愿者上门进行口述历史采访记录。','老兵采访'),
('修复解放战争时期部队合影','一张1948年的部队合影照片，记录了某连队全体指战员。照片有多处折痕和破损。','照片修复'),
('采访对越自卫反击战老兵李叔','李叔是对越自卫反击战老兵，需要志愿者耐心采访记录他的战斗经历和战后生活。','老兵采访'),
('修复烈士遗属收藏的老照片','某烈士后代保存着几张先辈参军前的照片，希望通过数字化手段修复保存。','照片修复'),
('采访老兵陈爷爷的抗日故事','陈爷爷是新四军老战士，今年已97岁高龄。急需志愿者前往采访记录其抗日经历。','老兵采访'),
('修复八路军某部队老照片集','一批珍贵的八路军抗战时期照片需要修复，共计23张，对研究抗战历史具有重要价值。','照片修复'),
('采访志愿军老战士刘爷爷','刘爷爷曾参加长津湖战役，需要志愿者团队进行系统性的口述历史采集和整理工作。','老兵采访'),
('修复革命烈士全家福','一位革命烈士的唯一一张全家福照片已经严重损坏，急需数字化修复保存。','照片修复'),
('采访渡江战役亲历者赵奶奶','赵奶奶今年96岁，曾是渡江战役中的支前民工，她的亲身经历是珍贵的口述历史资料。','老兵采访'),
('赵一曼纪念馆文物登记与保护','对赵一曼纪念馆馆藏文物进行数字化登记、拍照建档和保存环境评估。','文物保护'),
('采访解放海南岛老战士','海南解放75周年之际，寻访曾参加海南岛战役的老战士，记录渡海作战的英雄事迹。','老兵采访'),
('整理东北抗联历史文献资料','收集整理东北抗联时期的信件、日记、命令等历史文献，进行电子化录入和分类归档。','资料整理'),
('采访百岁老红军吴爷爷','吴爷爷今年102岁，曾参加过长征。作为为数不多健在的红军老战士，急需采访记录。','老兵采访'),
('修复新四军老战士家庭合影','一组新四军老战士及其家属的珍贵合影照片，已出现发黄、褪色等问题。','照片修复'),
('董存瑞烈士陵园文物维护','协助隆化董存瑞烈士陵园进行碑文拓印、文物登记和日常维护工作。','文物保护'),
('整理狼牙山五壮士相关史料','搜集整理狼牙山五壮士战斗前后的历史文献、报道和回忆录。','资料整理'),
('修复左权将军家书原件照片','左权将军写给妻子刘志兰的多封家书照片因保存年代久远有所损坏，需精心修复。','照片修复'),
('赣东北苏区老战士访谈录','寻访方志敏将军曾战斗过的赣东北苏区，记录健在老兵的战斗故事。','老兵采访'),
('李大钊故居文物数字化影像采集','对乐亭故居内的生活用品进行高清拍摄与三维建模存档。','文物保护'),
('修复长征路上的卫生员旧照片','一组因潮湿严重发霉的长征卫生员合影需要精细化修复。','照片修复'),
('整理抗战时期晋察冀边区报刊资料','对散落在民间的抗战报纸进行扫描、识别与分类整理。','资料整理'),
('四行仓库守军后代联络与回访','通过社交媒体与实地走访，寻找并记录“八百壮士”后代的生活现状。','资料整理'),
('修复湘江战役烈士遗物照片','包含军帽、搪瓷缸及几张珍贵的个人头像照片修复。','照片修复'),
('百岁红军老战士口述实录系列','针对100岁以上的老红军进行系统性的视频采访与语音转录。','老兵采访'),
('太行山游击队战斗遗址考察','志愿者需前往实地核实战斗遗址现状，拍摄照片并撰写文字记录。','文物保护'),
('整理南昌起义将领家书原件','对起义将领的家书进行电子化处理，并翻译为现代白话。','资料整理'),
('修复援华志愿队老照片','记录二战期间国际友人参与中国抗战的珍贵瞬间修复。','照片修复');
