-- ★ 在宝塔 phpMyAdmin 里执行这个文件即可 ★

CREATE DATABASE IF NOT EXISTS `red-pulse` DEFAULT CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `red-pulse`;

SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS `feedbacks`;
DROP TABLE IF EXISTS `submissions`;
DROP TABLE IF EXISTS `projects`;
DROP TABLE IF EXISTS `replies`;
DROP TABLE IF EXISTS `letters`;
DROP TABLE IF EXISTS `martyrs`;
DROP TABLE IF EXISTS `users`;
SET FOREIGN_KEY_CHECKS = 1;
-- 用户
CREATE TABLE `users` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `username` VARCHAR(50) NOT NULL UNIQUE,
  `password` VARCHAR(255) NOT NULL,
  `role` ENUM('admin','volunteer') DEFAULT 'volunteer',
  `phone` VARCHAR(20) DEFAULT '',
  `wechat` VARCHAR(50) DEFAULT '',
  `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB;

-- 默认管理员 账号admin 密码admin123

-- 模拟志愿者用户（密码均为 123456）
-- 烈士（10位英雄）
-- 2. 烈士表 (tracks 改为 TEXT 解决长度问题)
CREATE TABLE `martyrs` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `name` VARCHAR(50) NOT NULL,
  `avatar` VARCHAR(255) DEFAULT '',
  `bio` TEXT,
  `tracks` TEXT, 
  `family_status` TEXT,
  `lat` DECIMAL(10,6) NOT NULL,
  `lng` DECIMAL(10,6) NOT NULL,
  `route` JSON,
  `route_labels` JSON,
  `timeline` JSON,
  `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB;

'[[104.62,28.75],[121.47,31.23],[114.30,30.59],[126.65,45.75]]','["宜宾","上海","武汉","哈尔滨"]',
'[{"year":"1905","event":"出生于四川宜宾","type":"birth"},{"year":"1926","event":"加入中国共产党","type":"milestone"},{"year":"1927","event":"赴莫斯科中山大学学习","type":"milestone"},{"year":"1932","event":"前往东北参加抗日斗争","type":"battle"},{"year":"1935","event":"任东北抗联团政委，战斗中负伤被俘","type":"battle"},{"year":"1936","event":"英勇就义于珠河县","type":"sacrifice"}]'),

('杨靖宇','杨靖宇（1905-1940），原名马尚德，河南确山人，东北抗日联军创建人和领导人之一。1927年领导确山农民暴动，后赴东北开展抗日武装斗争，创建和领导东北抗联第一路军。在白山黑水间与日寇殊死搏斗数年，1940年2月在吉林濛江县被日军重重包围，孤身作战壮烈殉国。牺牲后日军解剖其遗体，发现胃中仅有草根、树皮和棉絮，连敌人都为之震惊敬佩。','河南确山 → 东北 → 濛江县','妻子郭莲和两个孩子在他赴东北后失去联系，解放后经多方寻找得到妥善安置。长子马从云继承父志投身国防建设，后代均自强不息报效国家。',42.380000,126.810000,
'[[114.02,32.80],[123.43,41.80],[128.05,41.99],[126.81,42.38]]','["确山","沈阳","长白山","濛江"]',
'[{"year":"1905","event":"出生于河南确山","type":"birth"},{"year":"1927","event":"领导确山农民暴动","type":"milestone"},{"year":"1932","event":"在东北组建抗日武装","type":"battle"},{"year":"1936","event":"任东北抗联第一路军总司令","type":"milestone"},{"year":"1939","event":"在极寒中率部与日军周旋","type":"battle"},{"year":"1940","event":"壮烈殉国于濛江县","type":"sacrifice"}]'),

('刘胡兰','刘胡兰（1932-1947），山西文水县云周西村人，中国共产党最年轻的女烈士之一。自幼受革命思想熏陶，13岁参加妇女培训班投身革命，1946年加入中国共产党。1947年1月国民党阎锡山部突袭云周西村，年仅15岁的她面对敌人铡刀毫不畏惧，英勇就义。毛主席亲笔题词"生的伟大，死的光荣"，其精神感召了无数中华儿女。','山西文水县云周西村','父亲刘景谦、继母胡文秀坚定支持革命，刘胡兰牺牲后家人受到党和人民深切关怀。文水县建有刘胡兰纪念馆，其英雄事迹被编入教材，成为爱国主义教育的永恒丰碑。',37.440000,112.030000,
'[[112.03,37.44],[112.10,37.50]]','["文水县","云周西村"]',
'[{"year":"1932","event":"出生于山西文水县","type":"birth"},{"year":"1945","event":"参加妇女培训班，投身革命","type":"milestone"},{"year":"1946","event":"加入中国共产党","type":"milestone"},{"year":"1947","event":"英勇就义，年仅15岁","type":"sacrifice"}]'),

('黄继光','黄继光（1931-1952），四川中江人，中国人民志愿军特级英雄。出身贫苦农家，1951年报名参加志愿军入朝作战。1952年10月在上甘岭战役中，部队进攻597.9高地受阻于敌军地堡火力，他主动请缨担任爆破任务。在身负重伤弹药用尽的情况下，毅然用胸膛堵住敌人枪眼，为部队冲锋开辟通道，壮烈牺牲，年仅21岁。','四川中江 → 朝鲜上甘岭','母亲邓芳芝得知儿子牺牲后强忍悲痛，亲笔给志愿军将士写信表达忠诚与支持。家乡中江县建有黄继光纪念馆，母亲一生以儿子为荣，多次被评为拥军模范。',38.320000,127.120000,
'[[104.68,31.03],[106.55,29.56],[116.40,39.90],[124.38,39.95],[127.12,38.32]]','["中江","重庆","北京","丹东","上甘岭"]',
'[{"year":"1931","event":"出生于四川中江","type":"birth"},{"year":"1951","event":"参加中国人民志愿军","type":"milestone"},{"year":"1952.4","event":"随部队入朝作战","type":"battle"},{"year":"1952.10","event":"上甘岭战役，用身体堵住枪眼","type":"battle"},{"year":"1952.10","event":"壮烈牺牲，追授特级英雄","type":"sacrifice"}]'),

('邱少云','邱少云（1926-1952），重庆铜梁人，中国人民志愿军一级英雄。少年家境贫寒，1949年参加解放军，1951年赴朝作战。1952年10月在391高地反击战潜伏任务中，敌军燃烧弹引燃身旁伪装物，烈火蔓延全身。为不暴露500余名战友和整个作战计划，他咬紧牙关纹丝不动直至壮烈牺牲，年仅26岁。','重庆铜梁 → 朝鲜391高地','自幼父母双亡，由哥哥邱少华抚养长大。牺牲后被追授一级英雄称号，家乡铜梁建有邱少云烈士纪念馆，哥哥邱少华一生守护弟弟的荣誉与精神。',38.950000,127.030000,
'[[106.05,29.84],[106.55,29.56],[124.38,39.95],[127.03,38.95]]','["铜梁","重庆","丹东","391高地"]',
'[{"year":"1926","event":"出生于重庆铜梁","type":"birth"},{"year":"1949","event":"参加中国人民解放军","type":"milestone"},{"year":"1951","event":"赴朝作战","type":"battle"},{"year":"1952","event":"在391高地壮烈牺牲","type":"sacrifice"}]'),

('董存瑞','董存瑞（1929-1948），河北怀来人，解放战争时期著名战斗英雄。16岁参加八路军，作战勇猛，先后荣立大功三次、小功四次。1948年5月在解放隆化的战斗中，部队被敌军桥头碉堡猛烈火力压制。在找不到炸药支撑点的紧急关头，他毅然用左手托起炸药包，高喊"为了新中国，前进！"壮烈牺牲，年仅19岁。','河北怀来 → 承德隆化','父亲董全忠、母亲孙珍为朴实农民，儿子牺牲后悲痛万分却深感光荣。隆化县建有董存瑞烈士陵园，朱德总司令亲笔题写"舍身为国，永垂不朽"。',41.310000,117.730000,
'[[115.52,40.40],[116.97,40.97],[117.73,41.31]]','["怀来","丰宁","隆化"]',
'[{"year":"1929","event":"出生于河北怀来","type":"birth"},{"year":"1945","event":"参加八路军","type":"milestone"},{"year":"1947","event":"加入中国共产党","type":"milestone"},{"year":"1948","event":"手举炸药包炸毁碉堡，壮烈牺牲","type":"sacrifice"}]'),

('左权','左权（1905-1942），湖南醴陵人，八路军副参谋长，抗日战争中八路军牺牲的最高将领。黄埔军校一期毕业，后赴莫斯科中山大学和伏龙芝军事学院深造。1937年任八路军副参谋长赴太行山抗日，参与指挥百团大战等重大战役。1942年5月在日军大扫荡中于山西辽县十字岭突围战中壮烈殉国，年仅37岁。','湖南醴陵 → 延安 → 山西辽县','留有多封家书致妻子刘志兰和幼女左太北，字字含情句句深情。妻子在其牺牲后坚强抚养女儿成人，女儿左太北终生致力于收集整理父亲遗物。辽县后改名为左权县以永久纪念。',36.870000,113.380000,
'[[113.50,27.67],[109.49,36.60],[112.55,37.87],[113.38,36.87]]','["醴陵","延安","太行山","辽县"]',
'[{"year":"1905","event":"出生于湖南醴陵","type":"birth"},{"year":"1925","event":"加入中国共产党","type":"milestone"},{"year":"1934","event":"参加长征","type":"battle"},{"year":"1937","event":"任八路军副参谋长，赴太行山抗日","type":"battle"},{"year":"1942","event":"十字岭突围战中壮烈殉国","type":"sacrifice"}]'),

('江竹筠','江竹筠（1920-1949），四川自贡人，人称"江姐"，中国共产党优秀党员。1939年入党，长期从事地下工作。1947年随丈夫彭咏梧在川东组织武装斗争，丈夫牺牲后她强忍悲痛继续战斗。1948年因叛徒出卖被捕入渣滓洞监狱，面对酷刑始终坚贞不屈。1949年11月壮烈牺牲于歌乐山，年仅29岁。','四川自贡 → 重庆渣滓洞','留有遗书托孤于亲友，嘱咐"孩子们决不要娇养，粗服淡饭足矣"。丈夫彭咏梧先于她牺牲，儿子彭云在亲友抚养下长大成材，后成为知名学者。',29.560000,106.550000,
'[[104.77,29.35],[106.55,29.56]]','["自贡","重庆"]',
'[{"year":"1920","event":"出生于四川自贡","type":"birth"},{"year":"1939","event":"加入中国共产党","type":"milestone"},{"year":"1947","event":"随丈夫彭咏梧从事地下工作","type":"battle"},{"year":"1948","event":"被捕入渣滓洞监狱，受尽酷刑","type":"battle"},{"year":"1949","event":"壮烈牺牲于歌乐山","type":"sacrifice"}]'),

('张思德','张思德（1915-1944），四川仪陇人，全心全意为人民服务的光辉典范。1933年参加红军，经历长征到达延安，在部队中处处以身作则、勤勤恳恳。1944年9月在延安安塞执行烧炭任务时炭窑突然崩塌，他奋力将战友推出洞口自己却被埋在窑内，壮烈牺牲，年仅29岁。毛主席在其追悼会上发表了著名的《为人民服务》演讲。','四川仪陇 → 延安安塞','自幼家境贫寒被过继给邻居，养父母待他如亲生。牺牲后毛主席亲笔题词纪念，"为人民服务"五个大字成为中国共产党的根本宗旨，影响了一代又一代中国人。',36.870000,109.330000,
'[[106.30,31.27],[105.45,32.43],[107.03,33.07],[109.49,36.60],[109.33,36.87]]','["仪陇","广元","汉中","延安","安塞"]',
'[{"year":"1915","event":"出生于四川仪陇","type":"birth"},{"year":"1933","event":"参加红军","type":"milestone"},{"year":"1935","event":"随红军长征到达延安","type":"battle"},{"year":"1944","event":"在安塞烧炭时炭窑崩塌牺牲","type":"sacrifice"}]'),

('狼牙山五壮士','1941年秋，日军大规模扫荡晋察冀根据地，八路军战士马宝玉、葛振林、宋学义、胡德林、胡福才五人奉命掩护群众和主力转移。他们且战且退将敌军引向狼牙山主峰棋盘陀，弹药耗尽后用石头与敌人搏斗。面对悬崖峭壁五名壮士宁死不降，砸毁枪械后纵身跳下万丈深渊，三人壮烈牺牲，谱写了一曲气壮山河的英雄壮歌。','河北易县狼牙山','葛振林、宋学义跳崖后被山腰树枝挂住幸存，伤愈后继续战斗直至抗战胜利。三位烈士的家人受到政府和人民持续关怀，河北易县建有狼牙山五壮士纪念塔。',39.350000,115.500000,
'[[115.50,39.35],[115.52,39.42]]','["易县","狼牙山"]',
'[{"year":"1941.9","event":"日军大规模扫荡晋察冀根据地","type":"battle"},{"year":"1941.9.25","event":"五壮士据守狼牙山棋盘陀","type":"battle"},{"year":"1941.9.25","event":"弹尽后纵身跳崖，三人壮烈牺牲","type":"sacrifice"}]'),

('方志敏','方志敏（1899-1935），江西弋阳人，无产阶级革命家，赣东北革命根据地和红十军的主要创建人。他领导创建了闽浙赣革命根据地，1935年不幸被捕入狱，面对威逼利诱始终坚贞不屈，在狱中写下《清贫》《可爱的中国》等不朽名篇。同年8月在南昌英勇就义，"清贫"精神成为共产党人的精神标杆。','江西弋阳 → 赣东北 → 南昌下沙窝','妻子缪敏同为坚定的革命者，在丈夫牺牲后继续革命工作。子女后代秉承遗志为国家建设贡献力量，方志敏"爱国、清贫、奉献"的精神代代传承。','28.680000','115.890000',
'[[117.31,28.41],[117.61,28.91],[115.89,28.68]]','["弋阳","横峰","南昌"]',
'[{"year":"1899","event":"出生于江西弋阳","type":"birth"},{"year":"1924","event":"加入中国共产党","type":"milestone"},{"year":"1928","event":"领导弋横暴动","type":"battle"},{"year":"1935","event":"在南昌英勇就义","type":"sacrifice"}]'),

('李大钊','李大钊（1889-1927），河北乐亭人，中国共产党主要创始人之一，将马克思主义系统引入中国的先驱。早年留学日本，回国后在北京大学任教，积极传播新思想新文化。1920年发起成立北京共产主义小组，与陈独秀南北呼应创建中国共产党。1927年4月被军阀张作霖逮捕，面对绞刑从容就义，是中国革命的先驱。','河北乐亭 → 日本东京 → 北京','长子李葆华继承父志投身革命，后曾任中国人民银行行长、安徽省委书记等要职。后代均在各自岗位上为国家建设做出贡献，李大钊精神薪火相传。','39.900000','116.400000',
'[[118.91,39.42],[139.69,35.68],[116.40,39.90]]','["乐亭","东京","北京"]',
'[{"year":"1889","event":"出生于河北乐亭","type":"birth"},{"year":"1920","event":"发起成立北京共产主义小组","type":"milestone"},{"year":"1927","event":"在北京英勇就义","type":"sacrifice"}]'),

('蔡和森','蔡和森（1895-1931），湖南双峰人，中国共产党早期重要领导人。他是最早明确提出建立”中国共产党”并系统阐述建党理论的人。1919年赴法勤工俭学，与向警予结为革命伴侣，回国后担任中央多个重要职务。1931年在香港因叛徒出卖被捕，后在广州英勇就义。','湖南双峰 → 法国蒙达尼 → 广州','妻子向警予同为中共早期领导人和烈士，夫妻双双为革命献出生命。母亲葛健豪被称为”革命母亲”，全家多人投身革命，堪称满门忠烈。','23.120000','113.260000',
'[[112.20,27.41],[2.73,48.06],[113.26,23.12]]','["双峰","法国","广州"]',
'[{"year":"1895","event":"出生于上海","type":"birth"},{"year":"1919","event":"赴法勤工俭学","type":"milestone"},{"year":"1931","event":"在广州牺牲","type":"sacrifice"}]'),

('叶挺','叶挺（1896-1946），广东惠阳人，杰出的军事家、北伐名将。参与领导了南昌起义和广州起义，是中国人民解放军的创始人之一。抗战时期出任新四军军长，皖南事变中被国民党扣押长达五年。经党中央营救获释后不久，1946年4月因飞机失事不幸遇难。','广东惠阳 → 湖北武汉 → 延安','遗子叶正大后成为中国航空工业的奠基人之一，为国防科技做出重要贡献。叶挺在狱中写下著名的《囚歌》，"我渴望自由，但更渴望真理"成为传世名篇。','36.600000','109.490000',
'[[114.41,22.82],[114.30,30.59],[109.49,36.60]]','["惠阳","武汉","延安"]',
'[{"year":"1896","event":"出生于广东惠阳","type":"birth"},{"year":"1937","event":"任新四军军长","type":"milestone"},{"year":"1946","event":"因空难失事遇难","type":"sacrifice"}]'),

('张自忠','张自忠（1891-1940），山东临清人，国民革命军上将，二战中国战场阵亡的最高军衔将领。他先后参加台儿庄战役、随枣会战等重大战役屡立战功。1940年5月枣宜会战中亲率部队渡河迎战日军，在南瓜店与数倍于己的敌军激战，身中数弹壮烈殉国。','山东临清 → 北京 → 湖北宜城','殉国后被追授陆军上将衔，周恩来称他为”全国军人楷模”。北京、武汉等多个城市以”张自忠路”命名街道以资纪念，遗体被日军发现后亦列队致敬。','31.710000','112.250000',
'[[115.75,36.85],[116.40,39.90],[112.25,31.71]]','["临清","北京","宜城"]',
'[{"year":"1891","event":"出生于山东临清","type":"birth"},{"year":"1940","event":"枣宜会战激战南瓜店，壮烈殉国","type":"sacrifice"}]'),

('向警予','向警予（1895-1928），湖南溆浦人，中国共产党创始人之一和早期唯一的女中央委员，中国妇女运动先驱。1919年赴法勤工俭学，回国后担任中共中央妇女部首任部长，积极领导妇女解放运动和工人运动。1928年在武汉因叛徒出卖被捕，同年5月在汉口英勇就义，年仅33岁。','湖南溆浦 → 法国 → 武汉','临刑前面对围观群众慷慨陈词、高唱《国际歌》，尽显巾帼英雄本色。丈夫蔡和森三年后同样英勇就义，夫妻双烈传为革命佳话。','30.590000','114.300000',
'[[110.59,27.91],[114.30,30.59]]','["溆浦","武汉"]',
'[{"year":"1895","event":"出生于湖南溆浦","type":"birth"},{"year":"1928","event":"在武汉就义","type":"sacrifice"}]'),

('谢晋元','谢晋元（1905-1941），广东蕉岭人，淞沪会战中著名的民族英雄。1937年率领”八百壮士”坚守上海四行仓库四天四夜，以弱敌强抵抗日军疯狂进攻，震惊中外。后被迫退入公共租界，被困”孤军营”。1941年4月被汪伪收买的叛兵刺杀，壮烈牺牲。','广东蕉岭 → 上海四行仓库','妻子凌维诚在丈夫遇难后独力抚养四个年幼子女，含辛茹苦将孩子们培养成材。新中国成立后凌维诚多次受到政府表彰，谢晋元被追授陆军少将衔。','31.230000','121.470000',
'[[116.17,24.66],[121.47,31.23]]','["蕉岭","上海"]',
'[{"year":"1905","event":"出生于广东蕉岭","type":"birth"},{"year":"1937","event":"领导四行仓库保卫战","type":"battle"},{"year":"1941","event":"在上海遇刺牺牲","type":"sacrifice"}]'),

('夏明翰','夏明翰（1900-1928），湖南衡阳人，中国共产党早期著名革命家。出身名门却毅然投身革命，积极参加领导湖南农民运动和工人运动。1928年在武汉被捕，临刑前挥笔写下”砍头不要紧，只要主义真。杀了夏明翰，还有后来人”的就义诗，气壮山河，年仅28岁。','湖南衡阳 → 武汉 → 汉口','妻子郑家钧在丈夫牺牲后坚持抚养女儿，一生忠于革命理想。弟弟夏明震、夏明霹先后为革命牺牲，一门多烈士，满门忠义。','30.580000','114.270000',
'[[112.60,26.89],[114.27,30.58]]','["衡阳","汉口"]',
'[{"year":"1900","event":"出生于湖北秭归","type":"birth"},{"year":"1928","event":"在汉口就义","type":"sacrifice"}]'),

('关向应','关向应（1902-1946），辽宁金州人，满族，杰出的无产阶级革命家。长期与贺龙并肩作战，是红二方面军和八路军一二〇师的主要领导人之一。在长征和抗日战争期间英勇善战、功勋卓著，因长期艰苦作战积劳成疾，1946年7月病逝于延安。毛主席题词"忠心耿耿，为党为国"。','辽宁大连 → 荆州 → 延安','一生将全部精力奉献给革命事业，与贺龙情同手足。病逝后延安各界举行隆重追悼，毛主席、朱德等中央领导亲临致哀，其忠诚品格为后人敬仰。','36.600000','109.490000',
'[[121.71,39.10],[112.23,30.33],[109.49,36.60]]','["大连","荆州","延安"]',
'[{"year":"1902","event":"出生于辽宁金县","type":"birth"},{"year":"1946","event":"病逝于延安","type":"sacrifice"}]'),

('寻淮洲','寻淮洲（1912-1934），湖南浏阳人，红军著名青年将领。15岁参加革命，凭借出色军事才能迅速成长，19岁任师长，21岁任红七军团军团长，是红军史上最年轻的军团长之一。在反"围剿"战斗中英勇善战、指挥果断。1934年在安徽太平谭家桥战斗中身负重伤，壮烈牺牲，年仅22岁。','湖南浏阳 → 井冈山 → 安徽太平','牺牲时年仅22岁，尚未成家，短暂一生全部献给了革命事业。家乡浏阳建有寻淮洲烈士纪念碑，其英勇事迹被传颂至今。','30.150000','118.170000',
'[[113.63,28.14],[114.16,26.57],[118.17,30.15]]','["浏阳","井冈山","太平"]',
'[{"year":"1912","event":"出生于湖南浏阳","type":"birth"},{"year":"1934","event":"在安徽太平战斗中牺牲","type":"sacrifice"}]'),

('陈延年','陈延年（1898-1927），安徽安庆人，陈独秀长子，中国共产党早期领导人之一。早年赴法勤工俭学，回国后先后担任中共广东区委书记和江浙区委书记。1927年在上海被捕，面对酷刑宁死不屈，留下”革命者只有站着死，绝不跪下”的铮铮誓言，在龙华英勇就义，年仅29岁。','安庆 → 巴黎 → 广州 → 上海','胞弟陈乔年同为中共早期领导人，兄弟二人先后在上海龙华英勇就义，前后相隔不到一年。父亲陈独秀闻讯悲痛欲绝，兄弟双烈震惊革命阵营。',31.230000,121.470000,
'[[117.05,30.53],[2.35,48.85],[113.26,23.12],[121.47,31.23]]','["安庆","巴黎","广州","上海"]',
'[{"year":"1898","event":"出生于安徽安庆","type":"birth"},{"year":"1919","event":"赴法勤工俭学","type":"milestone"},{"year":"1924","event":"回国任中共广东区委书记","type":"milestone"},{"year":"1927","event":"在上海龙华英勇就义","type":"sacrifice"}]'),

('陈乔年','陈乔年（1902-1928），安徽安庆人，陈独秀次子，中共中央委员。青年时赴法勤工俭学，后赴莫斯科学习马克思主义，回国后担任党的重要职务。1928年因叛徒出卖在上海被捕，狱中受尽酷刑仍坚贞不屈。就义前从容笑对敌人，留下”让子孙后代享受前人披荆斩棘的幸福吧”的不朽名言，年仅26岁。','安庆 → 莫斯科 → 武汉 → 上海','与哥哥陈延年先后在上海龙华就义，兄弟二人以鲜血书写了对信仰的忠诚。妻子史静仪独力抚养遗腹子，陈氏兄弟的故事感动了无数中国人。',31.170000,121.450000,
'[[117.05,30.53],[37.61,55.75],[114.30,30.59],[121.45,31.17]]','["安庆","莫斯科","武汉","上海"]',
'[{"year":"1902","event":"出生于安徽安庆","type":"birth"},{"year":"1925","event":"从莫斯科回国工作","type":"milestone"},{"year":"1927","event":"参加中共五大","type":"milestone"},{"year":"1928","event":"在上海龙华就义，年仅26岁","type":"sacrifice"}]'),

('瞿秋白','瞿秋白（1899-1935），江苏常州人，中国共产党早期主要领导人，卓越的革命家、理论家和文学家。曾两度赴苏联，是最早将《国际歌》翻译成中文的人之一。1927年主持"八七会议"挽救革命，后在上海领导左翼文化运动，与鲁迅结下深厚友谊。1935年在福建被捕，6月在长汀从容走向刑场，沿途高唱《国际歌》，英勇就义。','常州 → 莫斯科 → 上海 → 福建长汀','临终前从容淡定，留下《多余的话》等珍贵文献。妻子杨之华在他牺牲后继续革命，一生忠于丈夫遗志，为整理传播瞿秋白著作做出重要贡献。',25.830000,116.350000,
'[[119.95,31.78],[37.61,55.75],[121.47,31.23],[116.35,25.83]]','["常州","莫斯科","上海","长汀"]',
'[{"year":"1899","event":"出生于江苏常州","type":"birth"},{"year":"1927","event":"主持“八七会议”","type":"milestone"},{"year":"1931","event":"在上海领导左翼文化运动","type":"milestone"},{"year":"1935","event":"在福建长汀英勇就义","type":"sacrifice"}]'),

('赵世炎','赵世炎（1901-1927），重庆酉阳人，中国共产党早期杰出的无产阶级革命家和工人运动领袖。1921年赴法勤工俭学，与周恩来发起成立旅欧中国少年共产党。回国后投入工人运动，是五卅运动重要领导者。1927年领导上海工人第三次武装起义取得胜利，随后被捕英勇就义，年仅26岁。','重庆 → 巴黎 → 莫斯科 → 上海','妻子夏之栩在丈夫牺牲后继续从事革命工作。赵世炎一生虽短暂，但对中国工人运动贡献永载史册，重庆酉阳建有赵世炎故居纪念馆。',31.240000,121.480000,
'[[108.91,28.84],[2.35,48.85],[121.48,31.24]]','["酉阳","巴黎","上海"]',
'[{"year":"1901","event":"出生于四川酉阳","type":"birth"},{"year":"1921","event":"与周恩来发起成立旅欧中国少年共产党","type":"milestone"},{"year":"1927","event":"领导上海工人第三次武装起义","type":"battle"},{"year":"1927","event":"在上海就义","type":"sacrifice"}]'),

('戴安兰','戴安兰（1904-1942），安徽无为人，国民革命军第200师师长，杰出的抗日名将。毕业于黄埔军校第三期，1939年参加昆仑关战役重创日军精锐。1942年随中国远征军入缅作战，在同古保卫战中以寡敌众。后在撤退途中遭日军伏击身负重伤，在缅甸茅邦壮烈殉国，年仅38岁。','安徽无为 → 昆明 → 缅甸同古','牺牲前留下绝命家书三封，分别致妻子、父亲和友人，字字血泪感人至深。毛主席亲作挽诗悼念，遗体归国时沿途十万军民自发迎灵致哀。',24.870000,102.720000,
'[[117.91,31.30],[102.72,24.87],[96.46,18.91],[97.50,24.50]]','["无为","昆明","缅甸同古","茅邦"]',
'[{"year":"1904","event":"出生于安徽无为","type":"birth"},{"year":"1924","event":"报考黄埔军校","type":"milestone"},{"year":"1939","event":"参加昆仑关战役","type":"battle"},{"year":"1942","event":"率部入缅作战，伤重牺牲","type":"sacrifice"}]'),

('赵尚志','赵尚志（1908-1942），辽宁朝阳人，东北抗日联军创建人和主要领导人之一，与杨靖宇齐名并称"南杨北赵"。毕业于黄埔军校第四期，1933年领导创建珠河反日游击队。他身经百战、智勇双全，令日伪军闻风丧胆。1942年2月在梧桐河作战中负伤被俘，面对审讯痛斥日本侵略者，壮烈牺牲。','辽宁朝阳 → 哈尔滨 → 佳木斯','牺牲后遗体被日军残忍肢解投入松花江，直到2004年才找到头颅遗骨并安葬。其妹赵尚文一生致力于搜集哥哥的革命事迹，英名永垂不朽。',46.650000,130.310000,
'[[120.45,41.57],[126.65,45.75],[130.31,46.65]]','["朝阳","哈尔滨","佳木斯"]',
'[{"year":"1908","event":"出生于辽宁朝阳","type":"birth"},{"year":"1925","event":"入黄埔军校第四期学习","type":"milestone"},{"year":"1933","event":"创建珠河反日游击队","type":"battle"},{"year":"1942","event":"在战斗中负伤被俘，壮烈牺牲","type":"sacrifice"}]'),

('刘志丹','刘志丹（1903-1936），陕西保安（今志丹县）人，西北红军和西北革命根据地的主要创建人之一。黄埔军校第四期毕业，回到陕北后创建了陕甘边革命根据地，为中央红军长征提供了宝贵的落脚点。1936年4月在率部东征战斗中不幸中弹牺牲，年仅33岁。','陕西保安 → 黄埔军校 → 陕北 → 山西三交','毛主席亲笔题词”群众领袖，民族英雄”高度评价。妻子同桂荣在其牺牲后坚持革命工作，保安县改名为志丹县以永久纪念这位英雄。',37.130000,110.480000,
'[[108.56,36.85],[113.30,23.12],[108.56,36.85],[110.48,37.13]]','["志丹县","广州","陕北","山西三交"]',
'[{"year":"1903","event":"出生于陕西北安","type":"birth"},{"year":"1931","event":"组建西北反帝抗日游击队","type":"milestone"},{"year":"1935","event":"与中央红军胜利会师","type":"milestone"},{"year":"1936","event":"在东征战役中壮烈牺牲","type":"sacrifice"}]'),

('恽代英','恽代英（1895-1931），祖籍江苏常州，中国共产党早期青年运动领导人之一，被誉为”中国青年热爱的领袖”。创办利群书社传播进步思想，担任黄埔军校政治教官，参与领导南昌起义和广州起义。1930年在上海被捕，1931年4月在南京雨花台英勇就义，年仅36岁。','常州 → 武汉 → 上海 → 南京','牺牲前在狱中写下感人至深的《狱中诗》，以诗言志表达对革命必胜的坚定信念。他一生致力于青年教育，被周恩来称为”中国革命青年的楷模”。',32.060000,118.790000,
'[[119.95,31.78],[114.30,30.59],[121.47,31.23],[118.79,32.06]]','["常州","武汉","上海","南京"]',
'[{"year":"1895","event":"出生于湖北武昌","type":"birth"},{"year":"1920","event":"创办利群书社","type":"milestone"},{"year":"1923","event":"任中国社会主义青年团执委会候补委员","type":"milestone"},{"year":"1931","event":"在南京雨花台就义","type":"sacrifice"}]'),

('彭湃','彭湃（1896-1929），广东海丰人，中国农民革命运动先驱，被毛主席誉为”农民运动大王”。出身地主家庭却毅然当众烧毁自家田契分给佃农。1922年创办海丰县总农会开创中国农民运动先河，1927年领导建立海陆丰苏维埃政权。1929年因叛徒出卖在上海被捕，英勇就义。','广东海丰 → 东京 → 上海','全家为革命牺牲多人，被誉为”满门忠烈”。他烧掉祖传田契的壮举震撼了当时的中国社会，其无私精神成为共产党人不忘初心的生动诠释。',22.970000,115.320000,
'[[115.32,22.97],[139.69,35.68],[115.32,22.97],[121.47,31.23]]','["海丰","东京","海丰","上海"]',
'[{"year":"1896","event":"出生于广东海丰","type":"birth"},{"year":"1922","event":"成立海丰县总农会","type":"milestone"},{"year":"1927","event":"建立海陆丰苏维埃政府","type":"battle"},{"year":"1929","event":"在上海龙华被杀害","type":"sacrifice"}]'),

('韦拔群','韦拔群（1894-1932），广西东兰人，壮族，杰出的农民运动领袖，百色起义领导人之一。三次赴广州学习革命理论，回乡后发动组织农民运动。1929年与邓小平、张云逸共同领导百色起义，建立红七军和右江苏维埃政权，被誉为"广西农民运动的旗帜"。1932年因叛徒出卖在东兰被害。','广西东兰 → 广州 → 百色','全家先后有20余人为革命牺牲，满门忠烈令人敬佩。邓小平称他为"人民的英雄，壮族的骄傲"，东兰县建有韦拔群纪念馆。',24.510000,107.370000,
'[[107.37,24.51],[113.26,23.12],[106.61,23.90],[107.37,24.51]]','["东兰","广州","百色","东兰"]',
'[{"year":"1894","event":"出生于广西东兰","type":"birth"},{"year":"1926","event":"入广州农民运动讲习所学习","type":"milestone"},{"year":"1929","event":"领导百色起义","type":"battle"},{"year":"1932","event":"被叛徒杀害于东兰","type":"sacrifice"}]'),

('陈康容','陈康容（1915-1940），福建永定人，出生于缅甸华侨家庭，闽西著名的女英雄。自幼海外生活优越，但心系祖国。1937年抗战爆发后毅然回国投身抗日救亡运动，1938年加入中国共产党在闽西开展地下工作。1940年被国民党顽固派逮捕，面对酷刑坚贞不屈，在刑场上高呼革命口号英勇就义，年仅25岁。','缅甸 → 厦门 → 永定','面对严刑拷打写下”青春献给党，热血洒闽西”的誓言。作为归国华侨她放弃优渥生活为祖国献出年轻生命，其赤子之心感动了无数海内外同胞。',25.040000,116.730000,
'[[96.17,16.86],[118.08,24.48],[116.73,25.04]]','["缅甸仰光","厦门","永定"]',
'[{"year":"1915","event":"出生于缅甸","type":"birth"},{"year":"1937","event":"抗战爆发，毅然回国","type":"milestone"},{"year":"1938","event":"加入中国共产党","type":"milestone"},{"year":"1940","event":"在福建永定被捕就义","type":"sacrifice"}]'),

('吴焕先','吴焕先（1907-1935），河南新县人，红二十五军的主要创建者和领导人，被誉为长征中的”军魂”。17岁参加革命，1934年率红二十五军从大别山出发开始长征，以不足三千人兵力一路突破重围，是最先到达陕北的长征部队。1935年8月在甘肃泾川渡河战斗中身先士卒，壮烈牺牲，年仅28岁。','河南新县 → 陕南 → 甘肃泾川','全家六口有四人先后被敌人杀害，家破人亡却更坚定了革命意志。他在掩护部队渡河时中弹牺牲，全军将士闻讯痛哭，誓死为军长报仇。',35.330000,107.360000,
'[[114.87,31.63],[109.00,34.00],[107.36,35.33]]','["新县","陕南","泾川"]',
'[{"year":"1907","event":"出生于河南新县","type":"birth"},{"year":"1927","event":"参加黄麻起义","type":"battle"},{"year":"1934","event":"率红二十五军开始长征","type":"battle"},{"year":"1935","event":"在甘肃泾川战斗中牺牲","type":"sacrifice"}]'),

('罗炳辉','罗炳辉（1897-1946），云南彝良人，杰出的无产阶级军事家，从奴隶到将军的传奇人物。出身贫苦，少年时当过矿工。1929年领导吉安起义加入红军，抗战时期任新四军第五支队司令员，创造了多种游击战术。毛泽东称赞他为”战略骑兵”。1946年因病逝于前线，年仅49岁。','云南彝良 → 江西 → 安徽淮南','从云南彝良贫苦家庭走出，经历了从奴隶到将军的人生传奇。他的故事被誉为”中国革命的缩影”，云南彝良建有罗炳辉将军纪念馆。',32.490000,118.290000,
'[[104.05,27.62],[115.89,28.68],[118.29,32.49]]','["彝良","南昌","淮南"]',
'[{"year":"1897","event":"出生于云南彝良","type":"birth"},{"year":"1929","event":"领导吉安起义","type":"battle"},{"year":"1937","event":"任新四军第五支队司令员","type":"milestone"},{"year":"1946","event":"病逝于山东兰陵临沂一线","type":"sacrifice"}]'),

('张太雷','张太雷（1898-1927），江苏常州人，中国共产党早期重要领导人，中国社会主义青年团创建人之一。他是第一个被派往共产国际工作的中共党员。1927年12月领导发动广州起义，亲临前线指挥战斗，不幸遭敌人伏击壮烈牺牲，年仅29岁，是中共历史上第一位牺牲在战斗前线的中央委员。','常州 → 莫斯科 → 广州','牺牲在广州起义战斗第一线，是中共首位牺牲在一线的中央委员。妻子王一知在丈夫牺牲后继续革命工作，后代继承先烈遗志报效国家。',23.120000,113.260000,
'[[119.95,31.78],[37.61,55.75],[113.26,23.12]]','["常州","莫斯科","广州"]',
'[{"year":"1898","event":"出生于江苏常州","type":"birth"},{"year":"1921","event":"赴莫斯科任共产国际代表","type":"milestone"},{"year":"1927","event":"领导广州起义并壮烈牺牲","type":"sacrifice"}]'),

('黄公略','黄公略（1898-1931），湖南湘乡人，红军杰出将领、军事家。毕业于黄埔军校第三期，1928年与彭德怀共同领导了著名的平江起义，创建红五军。在中央苏区反”围剿”中屡建奇功，毛主席词中写下”偏师借重黄公略”的赞誉。1931年在江西吉安遭敌机空袭不幸牺牲，年仅33岁。','湖南湘乡 → 井冈山 → 江西吉安','平江起义三大领导者之一，与彭德怀、滕代远并肩作战。牺牲后毛主席亲自主持追悼会，中华苏维埃共和国将吉安东固改名为公略县以纪念。',27.080000,115.020000,
'[[112.52,27.73],[113.58,28.70],[115.02,27.08]]','["湘乡","平江","吉安"]',
'[{"year":"1898","event":"出生于湖南湘乡","type":"birth"},{"year":"1928","event":"与彭德怀领导平江起义","type":"battle"},{"year":"1931","event":"在江西南安遭遇空袭牺牲","type":"sacrifice"}]');
-- 4. 家书表 (确保 martyr_id 对应)
CREATE TABLE `letters` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `martyr_id` INT UNSIGNED NOT NULL,
  `content` TEXT NOT NULL,
  `photos` JSON,
  `ai_explanation` TEXT,
  FOREIGN KEY (`martyr_id`) REFERENCES `martyrs`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB;


(2,'同志们：\n\n我们在东北抗日已经多年了。面对强大的敌人和极端恶劣的环境，我们从未放弃抗日信念。\n\n即便是在冰天雪地中，即便是弹尽粮绝，我们也要战斗到最后一刻。因为我们的身后，是我们的祖国，是我们的人民。\n\n我相信，最终的胜利一定属于中国人民！\n\n杨靖宇','[{"url":"/photos/yangjingyu/yangjingyu1.jpg","desc":"杨靖宇历史照片 (1)"},{"url":"/photos/yangjingyu/yangjingyu2.png","desc":"杨靖宇历史照片 (2)"},{"url":"/photos/yangjingyu/yangjingyu3.jpg","desc":"杨靖宇历史照片 (3)"},{"url":"/photos/yangjingyu/yangjingyu4.jpg","desc":"杨靖宇历史照片 (4)"},{"url":"/photos/yangjingyu/yangjingyu5.jpg","desc":"杨靖宇历史照片 (5)"}]','杨靖宇将军牺牲后，日军解剖他的遗体，发现胃里只有树皮和棉絮，没有一粒粮食，连敌人都为之震惊和敬佩。'),

(3,'乡亲们：\n\n我刘胡兰虽然年纪小，但我知道什么是正义，什么是邪恶。共产党是为穷人谋幸福的，我愿意为共产党的事业献出一切。\n\n怕死不当共产党员！我不怕死，我要为人民而死！\n\n刘胡兰','[{"url":"/photos/liuhulan/liuhulan%20(1).jpg","desc":"刘胡兰历史照片 (1)"},{"url":"/photos/liuhulan/liuhulan%20(2).jpg","desc":"刘胡兰历史照片 (2)"},{"url":"/photos/liuhulan/liuhulan%20(3).jpg","desc":"刘胡兰历史照片 (3)"},{"url":"/photos/liuhulan/liuhulan%20(4).jpg","desc":"刘胡兰历史照片 (4)"},{"url":"/photos/liuhulan/liuhulan%20(5).jpg","desc":"刘胡兰历史照片 (5)"},{"url":"/photos/liuhulan/liuhulan%20(6).jpg","desc":"刘胡兰历史照片 (6)"}]','毛主席亲笔为她题词"生的伟大，死的光荣"，这八个字成为中华民族英雄精神的永恒象征。'),

(4,'亲爱的祖国：\n\n请原谅我不能再为你效力了。但请相信，我的每一滴血都是为了你而流。\n\n战友们，冲啊！为了祖国，为了人民，冲啊！\n\n黄继光','[{"url":"/photos/huangjiguang/huangjiguang%20(1).jpg","desc":"黄继光历史照片 (1)"},{"url":"/photos/huangjiguang/huangjiguang%20(2).jpg","desc":"黄继光历史照片 (2)"},{"url":"/photos/huangjiguang/huangjiguang%20(3).jpg","desc":"黄继光历史照片 (3)"},{"url":"/photos/huangjiguang/huangjiguang%20(4).jpg","desc":"黄继光历史照片 (4)"},{"url":"/photos/huangjiguang/huangjiguang%20(5).jpg","desc":"黄继光历史照片 (5)"},{"url":"/photos/huangjiguang/huangjiguang%20(6).jpg","desc":"黄继光历史照片 (6)"}]','黄继光在上甘岭战役中用胸膛堵住敌人枪眼，为部队冲锋开辟道路，体现了"最可爱的人"的崇高品质。'),

(5,'战友们：\n\n纪律是胜利的保证。我宁可被火烧死，也不能暴露目标，不能让整个潜伏计划失败。\n\n为了胜利，我愿意付出一切代价。\n\n邱少云','[{"url":"/photos/qiushaoyun/qiushaoyun%20(1).jpg","desc":"邱少云历史照片 (1)"},{"url":"/photos/qiushaoyun/qiushaoyun%20(2).jpg","desc":"邱少云历史照片 (2)"},{"url":"/photos/qiushaoyun/qiushaoyun%20(3).jpg","desc":"邱少云历史照片 (3)"},{"url":"/photos/qiushaoyun/qiushaoyun%20(4).jpg","desc":"邱少云历史照片 (4)"},{"url":"/photos/qiushaoyun/qiushaoyun%20(5).jpg","desc":"邱少云历史照片 (5)"}]','邱少云在烈火中纹丝不动整整半个多小时直至壮烈牺牲，钢铁般的意志力令人肃然起敬。'),

(6,'连长，让我去吧！\n\n为了新中国，前进！\n\n董存瑞','[{"url":"/photos/dongcunrui/dongcunrui%20(1).jpg","desc":"董存瑞历史照片 (1)"},{"url":"/photos/dongcunrui/dongcunrui%20(2).jpg","desc":"董存瑞历史照片 (2)"},{"url":"/photos/dongcunrui/dongcunrui%20(3).jpg","desc":"董存瑞历史照片 (3)"},{"url":"/photos/dongcunrui/dongcunrui%20(4).jpg","desc":"董存瑞历史照片 (4)"},{"url":"/photos/dongcunrui/dongcunrui%20(5).jpg","desc":"董存瑞历史照片 (5)"},{"url":"/photos/dongcunrui/dongcunrui%20(6).jpg","desc":"董存瑞历史照片 (6)"},{"url":"/photos/dongcunrui/dongcunrui%20(7).jpg","desc":"董存瑞历史照片 (7)"}]','董存瑞在总攻隆化城的战斗中，手举炸药包炸毁敌桥头碉堡，年仅19岁壮烈牺牲。"为了新中国，前进！"成为一代人的精神号角。'),

(7,'志兰：\n\n亲爱的，别时容易见时难。分离二十一个月了，何日相聚？念、念、念、念！\n\n愿在党的整顿之风下各自努力，力求进步吧，以进步来安慰自己，以进步来酬报别后衷情。\n\n左权','[{"url":"/photos/zuoquan/zuoquan%20(1).jpg","desc":"左权历史照片 (1)"},{"url":"/photos/zuoquan/zuoquan%20(2).jpg","desc":"左权历史照片 (2)"},{"url":"/photos/zuoquan/zuoquan%20(3).jpg","desc":"左权历史照片 (3)"},{"url":"/photos/zuoquan/zuoquan%20(4).jpg","desc":"左权历史照片 (4)"},{"url":"/photos/zuoquan/zuoquan%20(5).jpg","desc":"左权历史照片 (5)"},{"url":"/photos/zuoquan/zuoquan%20(6).jpg","desc":"左权历史照片 (6)"}]','这是左权将军写给妻子刘志兰的家书，字字含情。左权是抗日战争中八路军牺牲的最高将领，山西辽县后更名为左权县以纪念他。'),

(8,'竹安弟：\n\n友人告知我你曾来信，未收到。我们在牢中，一切均好，不必挂念。\n\n盼教以踏着父母之足迹，以建设新中国为志，为共产主义革命事业奋斗到底。\n\n孩子们决不要娇养，粗服淡饭足矣。\n\n江竹筠','[{"url":"/photos/jiangzhuyun/jiangzhuyun%20(1).jpg","desc":"江竹筠历史照片 (1)"},{"url":"/photos/jiangzhuyun/jiangzhuyun%20(2).jpg","desc":"江竹筠历史照片 (2)"},{"url":"/photos/jiangzhuyun/jiangzhuyun%20(3).jpg","desc":"江竹筠历史照片 (3)"},{"url":"/photos/jiangzhuyun/jiangzhuyun%20(4).jpg","desc":"江竹筠历史照片 (4)"},{"url":"/photos/jiangzhuyun/jiangzhuyun%20(5).jpg","desc":"江竹筠历史照片 (5)"},{"url":"/photos/jiangzhuyun/jiangzhuyun%20(6).jpg","desc":"江竹筠历史照片 (6)"}]','江姐在狱中受尽十指穿钉等酷刑仍坚贞不屈，遗书中"孩子们决不要娇养"体现了革命者朴素而坚定的信仰。'),

(9,'同志们：\n\n我是一个普普通通的战士，做的也是普普通通的事情。能为人民服务，是我最大的光荣。\n\n张思德','[{"url":"/photos/zhangsidei/zhangsidei%20(1).jpg","desc":"张思德历史照片 (1)"},{"url":"/photos/zhangsidei/zhangsidei%20(2).jpg","desc":"张思德历史照片 (2)"},{"url":"/photos/zhangsidei/zhangsidei%20(3).jpg","desc":"张思德历史照片 (3)"},{"url":"/photos/zhangsidei/zhangsidei%20(4).jpg","desc":"张思德历史照片 (4)"},{"url":"/photos/zhangsidei/zhangsidei%20(5).jpg","desc":"张思德历史照片 (5)"}]','毛主席在张思德追悼会上发表了著名的《为人民服务》演讲："人固有一死，或重于泰山，或轻于鸿毛。为人民利益而死，就比泰山还重。"'),

(10,'战友们：\n\n身后就是老百姓，我们绝不能后退一步！子弹打完了，就用石头砸！\n\n宁死不当俘虏！跳！\n\n——狼牙山五壮士','[{"url":"/photos/langyashanwuzhuangshi/langyashanwuzhuangshi%20(1).jpg","desc":"狼牙山五壮士历史照片 (1)"},{"url":"/photos/langyashanwuzhuangshi/langyashanwuzhuangshi%20(2).jpg","desc":"狼牙山五壮士历史照片 (2)"},{"url":"/photos/langyashanwuzhuangshi/langyashanwuzhuangshi%20(3).jpg","desc":"狼牙山五壮士历史照片 (3)"},{"url":"/photos/langyashanwuzhuangshi/langyashanwuzhuangshi%20(4).jpg","desc":"狼牙山五壮士历史照片 (4)"},{"url":"/photos/langyashanwuzhuangshi/langyashanwuzhuangshi%20(5).jpg","desc":"狼牙山五壮士历史照片 (5)"},{"url":"/photos/langyashanwuzhuangshi/langyashanwuzhuangshi%20(6).jpg","desc":"狼牙山五壮士历史照片 (6)"}]','五壮士在弹尽后纵身跳下悬崖，马宝玉、胡德林、胡福才壮烈牺牲，葛振林、宋学义被树枝挂住幸免于难。他们的壮举震撼了无数中华儿女。'),

(11,'缪敏：\n\n敌人只能砍下我们的头颅，决不能动摇我们的信仰！因为我们信仰的主义，乃是宇宙的真理！\n\n方志敏','[{“url”:”/photos/fangzhimin/fangzhimin%20(1).jpg”,”desc”:”方志敏历史照片 (1)”},{“url”:”/photos/fangzhimin/fangzhimin%20(2).jpg”,”desc”:”方志敏历史照片 (2)”},{“url”:”/photos/fangzhimin/fangzhimin%20(3).jpg”,”desc”:”方志敏历史照片 (3)”},{“url”:”/photos/fangzhimin/fangzhimin%20(4).jpg”,”desc”:”方志敏历史照片 (4)”},{“url”:”/photos/fangzhimin/fangzhimin%20(5).jpg”,”desc”:”方志敏历史照片 (5)”},{“url”:”/photos/fangzhimin/fangzhimin%20(6).jpg”,”desc”:”方志敏历史照片 (6)”}]','方志敏在狱中面对敌人的威逼利诱，始终保持共产党员的清贫与气节。'),
(12,'……我希望你们能继续我的遗志。中国，一定要强大起来！\n\n李大钊','[{“url”:”/photos/lidazhao/lidazhao%20(1).jpg”,”desc”:”李大钊历史照片 (1)”},{“url”:”/photos/lidazhao/lidazhao%20(2).jpg”,”desc”:”李大钊历史照片 (2)”},{“url”:”/photos/lidazhao/lidazhao%20(3).jpg”,”desc”:”李大钊历史照片 (3)”},{“url”:”/photos/lidazhao/lidazhao%20(4).jpg”,”desc”:”李大钊历史照片 (4)”},{“url”:”/photos/lidazhao/lidazhao%20(5).jpg”,”desc”:”李大钊历史照片 (5)”}]','李大钊临终前对未来的展望，是中国共产主义运动的火种。'),
(18,'杀了夏明翰，还有后来人！\n\n夏明翰','[{“url”:”/photos/xiaminghan/xiaminghan%20(1).jpg”,”desc”:”夏明翰历史照片 (1)”},{“url”:”/photos/xiaminghan/xiaminghan%20(2).jpg”,”desc”:”夏明翰历史照片 (2)”},{“url”:”/photos/xiaminghan/xiaminghan%20(3).jpg”,”desc”:”夏明翰历史照片 (3)”},{“url”:”/photos/xiaminghan/xiaminghan%20(4).jpg”,”desc”:”夏明翰历史照片 (4)”}]','极其简短却充满力量，是革命者对主义坚定不移的最好诠释。'),
(17,'兄弟们，我们守在这里，就是守住了中华民族的魂！\n\n谢晋元','[{“url”:”/photos/xiejinyuan/xiejinyuan%20(1).jpg”,”desc”:”谢晋元历史照片 (1)”},{“url”:”/photos/xiejinyuan/xiejinyuan%20(2).jpg”,”desc”:”谢晋元历史照片 (2)”},{“url”:”/photos/xiejinyuan/xiejinyuan%20(3).jpg”,”desc”:”谢晋元历史照片 (3)”},{“url”:”/photos/xiejinyuan/xiejinyuan%20(4).jpg”,”desc”:”谢晋元历史照片 (4)”},{“url”:”/photos/xiejinyuan/xiejinyuan%20(5).jpg”,”desc”:”谢晋元历史照片 (5)”}]','四行仓库保卫战中的动员令，极大地鼓舞了全国抗战信心。'),
(14,'挺虽身陷囹圄，然心系新四军之安危……\n\n叶挺','[{“url”:”/photos/yeting/yeting%20(1).jpg”,”desc”:”叶挺历史照片 (1)”},{“url”:”/photos/yeting/yeting%20(2).jpg”,”desc”:”叶挺历史照片 (2)”},{“url”:”/photos/yeting/yeting%20(3).jpg”,”desc”:”叶挺历史照片 (3)”},{“url”:”/photos/yeting/yeting%20(4).jpg”,”desc”:”叶挺历史照片 (4)”},{“url”:”/photos/yeting/yeting%20(5).jpg”,”desc”:”叶挺历史照片 (5)”},{“url”:”/photos/yeting/yeting%20(6).jpg”,”desc”:”叶挺历史照片 (6)”},{“url”:”/photos/yeting/yeting%20(7).jpg”,”desc”:”叶挺历史照片 (7)”},{“url”:”/photos/yeting/yeting%20(8).jpg”,”desc”:”叶挺历史照片 (8)”},{“url”:”/photos/yeting/yeting%20(9).jpg”,”desc”:”叶挺历史照片 (9)”}]','在皖南事变后叶挺所写的狱中诗及信件，体现了其不屈的风骨。'),
(13,'我们要走的路还很长，但终点一定是胜利。\n\n蔡和森','[{“url”:”/photos/caihesen/caihesen%20(1).jpg”,”desc”:”蔡和森历史照片 (1)”},{“url”:”/photos/caihesen/caihesen%20(2).jpg”,”desc”:”蔡和森历史照片 (2)”},{“url”:”/photos/caihesen/caihesen%20(3).jpg”,”desc”:”蔡和森历史照片 (3)”},{“url”:”/photos/caihesen/caihesen%20(4).jpg”,”desc”:”蔡和森历史照片 (4)”},{“url”:”/photos/caihesen/caihesen%20(5).jpg”,”desc”:”蔡和森历史照片 (5)”},{“url”:”/photos/caihesen/caihesen%20(6).jpg”,”desc”:”蔡和森历史照片 (6)”},{“url”:”/photos/caihesen/caihesen%20(7).jpg”,”desc”:”蔡和森历史照片 (7)”},{“url”:”/photos/caihesen/caihesen%20(8).jpg”,”desc”:”蔡和森历史照片 (8)”}]','蔡和森在艰苦环境下对党建理论的思考。'),
(15,'为国捐躯，义所难辞，誓与阵地共存亡！\n\n张自忠','[{“url”:”/photos/zhangzizhong/zhangzizhong%20(1).jpg”,”desc”:”张自忠历史照片 (1)”},{“url”:”/photos/zhangzizhong/zhangzizhong%20(2).jpg”,”desc”:”张自忠历史照片 (2)”},{“url”:”/photos/zhangzizhong/zhangzizhong%20(3).jpg”,”desc”:”张自忠历史照片 (3)”},{“url”:”/photos/zhangzizhong/zhangzizhong%20(4).jpg”,”desc”:”张自忠历史照片 (4)”},{“url”:”/photos/zhangzizhong/zhangzizhong%20(5).jpg”,”desc”:”张自忠历史照片 (5)”},{“url”:”/photos/zhangzizhong/zhangzizhong%20(6).jpg”,”desc”:”张自忠历史照片 (6)”},{“url”:”/photos/zhangzizhong/zhangzizhong%20(7).jpg”,”desc”:”张自忠历史照片 (7)”},{“url”:”/photos/zhangzizhong/zhangzizhong%20(8).jpg”,”desc”:”张自忠历史照片 (8)”}]','名将殉国前的决绝，展现了抗日民族英雄的英雄气概。'),
(16,'妇女的解放，是民族解放不可或缺的一部分。\n\n向警予','[{“url”:”/photos/xiangjingyu/xiejinyuan%20(1).jpg”,”desc”:”向警予历史照片 (1)”},{“url”:”/photos/xiangjingyu/xiejinyuan%20(2).jpg”,”desc”:”向警予历史照片 (2)”},{“url”:”/photos/xiangjingyu/xiejinyuan%20(3).jpg”,”desc”:”向警予历史照片 (3)”},{“url”:”/photos/xiangjingyu/xiejinyuan%20(4).jpg”,”desc”:”向警予历史照片 (4)”},{“url”:”/photos/xiangjingyu/xiejinyuan%20(5).jpg”,”desc”:”向警予历史照片 (5)”},{“url”:”/photos/xiangjingyu/xiejinyuan%20(6).jpg”,”desc”:”向警予历史照片 (6)”},{“url”:”/photos/xiangjingyu/xiejinyuan%20(7).jpg”,”desc”:”向警予历史照片 (7)”},{“url”:”/photos/xiangjingyu/xiejinyuan%20(8).jpg”,”desc”:”向警予历史照片 (8)”},{“url”:”/photos/xiangjingyu/xiejinyuan%20(9).jpg”,”desc”:”向警予历史照片 (9)”}]','展现了早期女性领导者对社会公平与革命关系的思考。'),
(19,'贺胡子，这一仗打完，咱再喝庆功酒！\n\n关向应','[{“url”:”/photos/guanxiangying/guanxiangying%20(1).jpg”,”desc”:”关向应历史照片 (1)”},{“url”:”/photos/guanxiangying/guanxiangying%20(2).jpg”,”desc”:”关向应历史照片 (2)”},{“url”:”/photos/guanxiangying/guanxiangying%20(3).jpg”,”desc”:”关向应历史照片 (3)”},{“url”:”/photos/guanxiangying/guanxiangying%20(4).jpg”,”desc”:”关向应历史照片 (4)”},{“url”:”/photos/guanxiangying/guanxiangying%20(5).jpg”,”desc”:”关向应历史照片 (5)”},{“url”:”/photos/guanxiangying/guanxiangying%20(6).jpg”,”desc”:”关向应历史照片 (6)”},{“url”:”/photos/guanxiangying/guanxiangying%20(7).jpg”,”desc”:”关向应历史照片 (7)”},{“url”:”/photos/guanxiangying/guanxiangying%20(8).jpg”,”desc”:”关向应历史照片 (8)”},{“url”:”/photos/guanxiangying/guanxiangying%20(9).jpg”,”desc”:”关向应历史照片 (9)”},{“url”:”/photos/guanxiangying/guanxiangying%20(10).jpg”,”desc”:”关向应历史照片 (10)”}]','体现了革命战友之间深厚的革命友谊。'),
(20,'连长，我冲在前面，你带弟兄们跟上！\n\n寻淮洲','[{“url”:”/photos/xunhuaizhou/xunhuaizhou%20(1).jpg”,”desc”:”寻淮洲历史照片 (1)”},{“url”:”/photos/xunhuaizhou/xunhuaizhou%20(2).jpg”,”desc”:”寻淮洲历史照片 (2)”},{“url”:”/photos/xunhuaizhou/xunhuaizhou%20(3).jpg”,”desc”:”寻淮洲历史照片 (3)”},{“url”:”/photos/xunhuaizhou/xunhuaizhou%20(4).jpg”,”desc”:”寻淮洲历史照片 (4)”}]','这位红军史上最年轻军团长的冲锋宣言。'),
(21,'……我的前途，我希望是充满着战斗的。我不愿过平庸的生活。为了真理，为了大多数人的幸福，我愿意奉献我的青春甚至生命。\n\n延年','[{“url”:”/photos/chenyannian/chenyannian%20(1).jpg”,”desc”:”陈延年历史照片 (1)”},{“url”:”/photos/chenyannian/chenyannian%20(1).png”,”desc”:”陈延年历史照片 (2)”},{“url”:”/photos/chenyannian/chenyannian%20(2).jpg”,”desc”:”陈延年历史照片 (3)”},{“url”:”/photos/chenyannian/chenyannian%20(3).jpg”,”desc”:”陈延年历史照片 (4)”},{“url”:”/photos/chenyannian/chenyannian%20(4).jpg”,”desc”:”陈延年历史照片 (5)”}]','陈延年烈士虽然家境显赫，却选择了最艰苦的一条路。这封信展现了他坚定的革命价值观。'),
(22,'战友们：\n\n如果我牺牲了，不要悲伤。请记住，我们是为了子孙后代能享受幸福而死。我们的血，会开出自由的花朵！\n\n乔年','[{“url”:”/photos/chenqiaonian/chenqiaonian%20(1).jpg”,”desc”:”陈乔年历史照片 (1)”},{“url”:”/photos/chenqiaonian/chenqiaonian%20(1).png”,”desc”:”陈乔年历史照片 (2)”},{“url”:”/photos/chenqiaonian/chenqiaonian%20(2).jpg”,”desc”:”陈乔年历史照片 (3)”},{“url”:”/photos/chenqiaonian/chenqiaonian%20(3).jpg”,”desc”:”陈乔年历史照片 (4)”},{“url”:”/photos/chenqiaonian/chenqiaonian%20(4).jpg”,”desc”:”陈乔年历史照片 (5)”}]','陈乔年在牺牲前对战友的嘱托，充满了浪漫的革命乐观主义精神。'),
(23,'我的中国，我的母亲。我为你而战，为你而死。我坚信，在不远的将来，你会成为一个富强、民主的新中国。\n\n秋白','[{“url”:”/photos/quqiubai/quqiubai%20(1).jpg”,”desc”:”瞿秋白历史照片 (1)”},{“url”:”/photos/quqiubai/quqiubai%20(2).jpg”,”desc”:”瞿秋白历史照片 (2)”},{“url”:”/photos/quqiubai/quqiubai%20(3).jpg”,”desc”:”瞿秋白历史照片 (3)”},{“url”:”/photos/quqiubai/quqiubai%20(4).jpg”,”desc”:”瞿秋白历史照片 (4)”},{“url”:”/photos/quqiubai/quqiubai%20(5).jpg”,”desc”:”瞿秋白历史照片 (5)”},{“url”:”/photos/quqiubai/quqiubai%20(6).jpg”,”desc”:”瞿秋白历史照片 (6)”},{“url”:”/photos/quqiubai/quqiubai%20(7).jpg”,”desc”:”瞿秋白历史照片 (7)”}]','瞿秋白博学多才，这封信流露了他作为文人与革命者双重身份对祖国的深情。'),
(24,'世炎：\n\n革命就像一团火，既然已经点燃，就绝不会熄灭！\n\n赵世炎','[{“url”:”/photos/zhaoshiyan/zhaoshiyan%20(1).jpg”,”desc”:”赵世炎历史照片 (1)”},{“url”:”/photos/zhaoshiyan/zhaoshiyan%20(2).jpg”,”desc”:”赵世炎历史照片 (2)”},{“url”:”/photos/zhaoshiyan/zhaoshiyan%20(3).jpg”,”desc”:”赵世炎历史照片 (3)”},{“url”:”/photos/zhaoshiyan/zhaoshiyan%20(4).jpg”,”desc”:”赵世炎历史照片 (4)”},{“url”:”/photos/zhaoshiyan/zhaoshiyan%20(5).jpg”,”desc”:”赵世炎历史照片 (5)”},{“url”:”/photos/zhaoshiyan/zhaoshiyan%20(6).jpg”,”desc”:”赵世炎历史照片 (6)”},{“url”:”/photos/zhaoshiyan/zhaoshiyan%20(7).jpg”,”desc”:”赵世炎历史照片 (7)”},{“url”:”/photos/zhaoshiyan/zhaoshiyan%20(8).jpg”,”desc”:”赵世炎历史照片 (8)”}]','赵世炎领导工人起义时的豪言壮志。'),
(25,'儿远征在外，不能尽孝膝前。此去缅甸，生死难料。若战死沙场，望双亲莫悲，儿为国尽忠，死而无憾！\n\n戴安兰','[{“url”:”/photos/daianlan/daianlan%20(1).jpg”,”desc”:”戴安兰历史照片 (1)”},{“url”:”/photos/daianlan/daianlan%20(2).jpg”,”desc”:”戴安兰历史照片 (2)”},{“url”:”/photos/daianlan/daianlan%20(3).jpg”,”desc”:”戴安兰历史照片 (3)”},{“url”:”/photos/daianlan/daianlan%20(4).jpg”,”desc”:”戴安兰历史照片 (4)”},{“url”:”/photos/daianlan/daianlan%20(5).jpg”,”desc”:”戴安兰历史照片 (5)”},{“url”:”/photos/daianlan/daianlan%20(6).jpg”,”desc”:”戴安兰历史照片 (6)”}]','这是戴安兰师长出征缅甸前写的绝命家书，感人至深。'),
(26,'……松花江的水很冷，但我的血是热的。只要还有一个中国人在，抗日就不会停止！\n\n赵尚志','[{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(1).jpg”,”desc”:”赵尚志历史照片 (1)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(2).jpg”,”desc”:”赵尚志历史照片 (2)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(3).jpg”,”desc”:”赵尚志历史照片 (3)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(4).jpg”,”desc”:”赵尚志历史照片 (4)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(5).jpg”,”desc”:”赵尚志历史照片 (5)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(6).jpg”,”desc”:”赵尚志历史照片 (6)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(7).jpg”,”desc”:”赵尚志历史照片 (7)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(8).jpg”,”desc”:”赵尚志历史照片 (8)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(9).jpg”,”desc”:”赵尚志历史照片 (9)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(10).jpg”,”desc”:”赵尚志历史照片 (10)”},{“url”:”/photos/zhaoshangzhi/zhaoshangzhi%20(11).jpg”,”desc”:”赵尚志历史照片 (11)”}]','赵尚志在极端残酷的东北抗联岁月里的坚定心声。'),
(27,'……我们要走农村包围城市的道路。这虽然难，但这是我们走向胜利的唯一途径。\n\n志丹','[{“url”:”/photos/liuzhidan/liuzhidan%20(1).jpg”,”desc”:”刘志丹历史照片 (1)”},{“url”:”/photos/liuzhidan/liuzhidan%20(2).jpg”,”desc”:”刘志丹历史照片 (2)”},{“url”:”/photos/liuzhidan/liuzhidan%20(3).jpg”,”desc”:”刘志丹历史照片 (3)”},{“url”:”/photos/liuzhidan/liuzhidan%20(4).jpg”,”desc”:”刘志丹历史照片 (4)”},{“url”:”/photos/liuzhidan/liuzhidan%20(5).jpg”,”desc”:”刘志丹历史照片 (5)”},{“url”:”/photos/liuzhidan/liuzhidan%20(6).jpg”,”desc”:”刘志丹历史照片 (6)”}]','刘志丹对西北根据地建设的深刻思考。'),
(28,'青年朋友们：\n\n中国是你们的，也是我们的，但归根结底是你们的。去奋斗吧，去创造吧！\n\n恽代英','[{“url”:”/photos/yundaiying/yundaiying%20(1).jpg”,”desc”:”恽代英历史照片 (1)”},{“url”:”/photos/yundaiying/yundaiying%20(2).jpg”,”desc”:”恽代英历史照片 (2)”},{“url”:”/photos/yundaiying/yundaiying%20(3).jpg”,”desc”:”恽代英历史照片 (3)”},{“url”:”/photos/yundaiying/yundaiying%20(4).jpg”,”desc”:”恽代英历史照片 (4)”},{“url”:”/photos/yundaiying/yundaiying%20(5).jpg”,”desc”:”恽代英历史照片 (5)”},{“url”:”/photos/yundaiying/yundaiying%20(6).jpg”,”desc”:”恽代英历史照片 (6)”},{“url”:”/photos/yundaiying/yundaiying%20(7).jpg”,”desc”:”恽代英历史照片 (7)”}]','恽代英对青年的鼓舞，时至今日依然震撼人心。'),
(29,'……我把自家的地分给了大家。大家有饭吃，有地种，这就是我最开心的事。\n\n彭湃','[{“url”:”/photos/pengpai/pengpai%20(1).jpg”,”desc”:”彭湃历史照片 (1)”},{“url”:”/photos/pengpai/pengpai%20(2).jpg”,”desc”:”彭湃历史照片 (2)”},{“url”:”/photos/pengpai/pengpai%20(3).jpg”,”desc”:”彭湃历史照片 (3)”},{“url”:”/photos/pengpai/pengpai%20(4).jpg”,”desc”:”彭湃历史照片 (4)”},{“url”:”/photos/pengpai/pengpai%20(5).jpg”,”desc”:”彭湃历史照片 (5)”}]','”农民大王”朴实的阶级情感。'),
(30,'拔群：\n\n我们壮家儿女，从来没有怕死鬼。为了全中国的穷苦兄弟，拼了！\n\n韦拔群','[{“url”:”/photos/weibaqun/weibaqun%20(1).jpg”,”desc”:”韦拔群历史照片 (1)”},{“url”:”/photos/weibaqun/weibaqun%20(2).jpg”,”desc”:”韦拔群历史照片 (2)”},{“url”:”/photos/weibaqun/weibaqun%20(3).jpg”,”desc”:”韦拔群历史照片 (3)”},{“url”:”/photos/weibaqun/weibaqun%20(4).jpg”,”desc”:”韦拔群历史照片 (4)”},{“url”:”/photos/weibaqun/weibaqun%20(5).jpg”,”desc”:”韦拔群历史照片 (5)”},{“url”:”/photos/weibaqun/weibaqun%20(6).jpg”,”desc”:”韦拔群历史照片 (6)”},{“url”:”/photos/weibaqun/weibaqun%20(7).jpg”,”desc”:”韦拔群历史照片 (7)”},{“url”:”/photos/weibaqun/weibaqun%20(8).jpg”,”desc”:”韦拔群历史照片 (8)”},{“url”:”/photos/weibaqun/weibaqun%20(9).jpg”,”desc”:”韦拔群历史照片 (9)”},{“url”:”/photos/weibaqun/weibaqun%20(10).jpg”,”desc”:”韦拔群历史照片 (10)”}]','体现了少数民族英烈对革命事业的无私奉献。'),
(31,'……青春是美丽的，但为真理而战的青春更美丽。我无悔回国，无悔入党。\n\n陈康容','[{“url”:”/photos/chenkangrong/chenkangrong%20(1).jpg”,”desc”:”陈康容历史照片 (1)”},{“url”:”/photos/chenkangrong/chenkangrong%20(2).jpg”,”desc”:”陈康容历史照片 (2)”},{“url”:”/photos/chenkangrong/chenkangrong%20(3).jpg”,”desc”:”陈康容历史照片 (3)”},{“url”:”/photos/chenkangrong/chenkangrong%20(4).jpg”,”desc”:”陈康容历史照片 (4)”},{“url”:”/photos/chenkangrong/chenkangrong%20(5).jpg”,”desc”:”陈康容历史照片 (5)”},{“url”:”/photos/chenkangrong/chenkangrong%20(6).jpg”,”desc”:”陈康容历史照片 (6)”},{“url”:”/photos/chenkangrong/chenkangrong%20(7).jpg”,”desc”:”陈康容历史照片 (7)”}]','归国华侨女烈士的赤子之心。'),
(32,'全军将士：\n\n长征虽然艰苦，但我们每走一步，就离胜利近了一步。大家坚持住！\n\n吴焕先','[{“url”:”/photos/wuhuanxian/wuhuanxian%20(1).jpg”,”desc”:”吴焕先历史照片 (1)”},{“url”:”/photos/wuhuanxian/wuhuanxian%20(2).jpg”,”desc”:”吴焕先历史照片 (2)”},{“url”:”/photos/wuhuanxian/wuhuanxian%20(3).jpg”,”desc”:”吴焕先历史照片 (3)”},{“url”:”/photos/wuhuanxian/wuhuanxian%20(4).jpg”,”desc”:”吴焕先历史照片 (4)”},{“url”:”/photos/wuhuanxian/wuhuanxian%20(5).jpg”,”desc”:”吴焕先历史照片 (5)”},{“url”:”/photos/wuhuanxian/wuhuanxian%20(6).jpg”,”desc”:”吴焕先历史照片 (6)”},{“url”:”/photos/wuhuanxian/wuhuanxian%20(7).jpg”,”desc”:”吴焕先历史照片 (7)”}]','红二十五军军魂的战斗动员。'),
(33,'……我是个当兵的，我只会用手里的枪保护百姓。只要我不倒下，敌人就别想进村！\n\n罗炳辉','[{“url”:”/photos/luobinghui/luobinghui%20(1).jpg”,”desc”:”罗炳辉历史照片 (1)”},{“url”:”/photos/luobinghui/luobinghui%20(2).jpg”,”desc”:”罗炳辉历史照片 (2)”},{“url”:”/photos/luobinghui/luobinghui%20(3).jpg”,”desc”:”罗炳辉历史照片 (3)”},{“url”:”/photos/luobinghui/luobinghui%20(4).jpg”,”desc”:”罗炳辉历史照片 (4)”},{“url”:”/photos/luobinghui/luobinghui%20(5).jpg”,”desc”:”罗炳辉历史照片 (5)”},{“url”:”/photos/luobinghui/luobinghui%20(6).jpg”,”desc”:”罗炳辉历史照片 (6)”},{“url”:”/photos/luobinghui/luobinghui%20(7).jpg”,”desc”:”罗炳辉历史照片 (7)”},{“url”:”/photos/luobinghui/luobinghui%20(8).jpg”,”desc”:”罗炳辉历史照片 (8)”},{“url”:”/photos/luobinghui/luobinghui%20(9).jpg”,”desc”:”罗炳辉历史照片 (9)”},{“url”:”/photos/luobinghui/luobinghui%20(10).jpg”,”desc”:”罗炳辉历史照片 (10)”},{“url”:”/photos/luobinghui/luobinghui%20(11).jpg”,”desc”:”罗炳辉历史照片 (11)”},{“url”:”/photos/luobinghui/luobinghui%20(12).jpg”,”desc”:”罗炳辉历史照片 (12)”},{“url”:”/photos/luobinghui/luobinghui%20(13).jpg”,”desc”:”罗炳辉历史照片 (13)”}]','罗将军朴素的军人天职感。'),
(34,'……广州的阳光很暖。我相信，等这一战打完，大家都能过上安稳日子。\n\n张太雷','[{“url”:”/photos/zhangtailei/zhangtailei%20(1).jpg”,”desc”:”张太雷历史照片 (1)”},{“url”:”/photos/zhangtailei/zhangtailei%20(2).jpg”,”desc”:”张太雷历史照片 (2)”},{“url”:”/photos/zhangtailei/zhangtailei%20(3).jpg”,”desc”:”张太雷历史照片 (3)”},{“url”:”/photos/zhangtailei/zhangtailei%20(4).jpg”,”desc”:”张太雷历史照片 (4)”},{“url”:”/photos/zhangtailei/zhangtailei%20(5).jpg”,”desc”:”张太雷历史照片 (5)”},{“url”:”/photos/zhangtailei/zhangtailei%20(6).jpg”,”desc”:”张太雷历史照片 (6)”}]','张太雷在广州起义爆发前的最后憧憬。'),
(35,'……井冈山是我们的根。我们要守住它，发扬它！\n\n黄公略','[{“url”:”/photos/huanggonglue/huanggonglue%20(1).jpg”,”desc”:”黄公略历史照片 (1)”},{“url”:”/photos/huanggonglue/huanggonglue%20(2).jpg”,”desc”:”黄公略历史照片 (2)”},{“url”:”/photos/huanggonglue/huanggonglue%20(3).jpg”,”desc”:”黄公略历史照片 (3)”},{“url”:”/photos/huanggonglue/huanggonglue%20(4).jpg”,”desc”:”黄公略历史照片 (4)”},{“url”:”/photos/huanggonglue/huanggonglue%20(5).jpg”,”desc”:”黄公略历史照片 (5)”},{“url”:”/photos/huanggonglue/huanggonglue%20(6).jpg”,”desc”:”黄公略历史照片 (6)”},{“url”:”/photos/huanggonglue/huanggonglue%20(7).jpg”,”desc”:”黄公略历史照片 (7)”},{“url”:”/photos/huanggonglue/huanggonglue%20(8).jpg”,”desc”:”黄公略历史照片 (8)”}]','早期红军将领对根据地建设的信念。');
-- 回信
CREATE TABLE `replies` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `letter_id` INT UNSIGNED NOT NULL,
  `user_id` INT UNSIGNED NOT NULL,
  `content` TEXT NOT NULL,
  `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (`letter_id`) REFERENCES `letters`(`id`) ON DELETE CASCADE,
  FOREIGN KEY (`user_id`) REFERENCES `users`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB;


-- 志愿项目（18个）
CREATE TABLE `projects` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `title` VARCHAR(200) NOT NULL,
  `description` TEXT,
  `category` ENUM('照片修复','老兵采访','文物保护','资料整理') DEFAULT '照片修复',
  `status` ENUM('进行中','已结束') DEFAULT '进行中',
  `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB;


-- 提交
CREATE TABLE `submissions` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `project_id` INT UNSIGNED NOT NULL,
  `user_id` INT UNSIGNED NOT NULL,
  `work_url` VARCHAR(500) DEFAULT '',
  `insight` TEXT,
  `review_status` ENUM('待审','通过','驳回') DEFAULT '待审',
  `certificate_code` VARCHAR(50) DEFAULT '',
  `reject_reason` VARCHAR(500) DEFAULT '',
  `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON DELETE CASCADE,
  FOREIGN KEY (`user_id`) REFERENCES `users`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB;

